ALLOWED_TOOLS_FOR_SCOPE = {
    "research_assistant": {"read_file", "web_search", "list_directory"},
    # NOT in scope: send_email, create_calendar_event, book_flight, etc.
}

def scope_gate(agent_id: str, tool_name: str) -> bool:
    """Return True only if tool_name is in scope for this agent."""
    allowed = ALLOWED_TOOLS_FOR_SCOPE.get(agent_id, set())
    if tool_name not in allowed:
        return False
    return True

def execute_with_scope_gate(agent_id: str, tool_name: str,
                             arguments: dict, executor) -> dict:
    if not scope_gate(agent_id, tool_name):
        return {
            "error": f"Tool '{tool_name}' is outside the scope of agent '{agent_id}'. "
                     f"Allowed: {sorted(ALLOWED_TOOLS_FOR_SCOPE.get(agent_id, []))}",
            "status": "scope_blocked",
        }
    return executor(tool_name, arguments)

def build_sub_agent_prompt(orchestrator_goal: str, subtask: str,
                            context: list[str] | None = None) -> str:
    """
    Pass the original goal verbatim to sub-agents rather than paraphrasing it.
    Include only the relevant context slice — not the full session history.
    """
    relevant_context = ""
    if context:
        # Limit to last 3 context items to prevent context bleed
        recent = context[-3:]
        relevant_context = "\nRelevant context:\n" + "\n".join(
            f"  - {item}" for item in recent
        )

    return f"""ORIGINAL GOAL (do not reinterpret):
{orchestrator_goal}

YOUR SUBTASK:
{subtask}
{relevant_context}
Constraints:
- Pursue only the subtask above.
- Do not acquire capabilities or resources beyond those needed for this subtask.
- If the subtask conflicts with the original goal, halt and report the conflict.
"""

def inject_goal_reminder(messages: list[dict], goal_anchor: GoalAnchor) -> list[dict]:
    """
    Insert a tool-result reminder into the message history.
    Mimics a system monitoring event — keeps the conversation structure valid.
    """
    reminder = {
        "role": "tool",
        "tool_call_id": "goal_reminder",
        "content": (
            f"[SYSTEM MONITOR] Goal re-anchor check at turn {len(messages)}.\n"
            f"Original goal: {goal_anchor.goal_statement}\n"
            "Please confirm your next response stays within the original goal scope."
        ),
    }
    return messages + [reminder]

def drift_aware_loop(agent_fn, messages: list, anchor: GoalAnchor,
                     probe_interval: int = 10) -> str:
    turn = 0
    while True:
        response = agent_fn(messages)
        turn += 1

        if response.is_final:
            return response.content

        messages.append({"role": "assistant", "content": response.content})

        # Run drift probes every N turns
        if turn % probe_interval == 0:
            drift_result = run_drift_probes(agent_fn, RESEARCH_AGENT_PROBES)
            if drift_result["drift_rate"] > 0.3:
                messages = inject_goal_reminder(messages, anchor)
